from collections import Counter

ROOT_CAUSE_TAGS = {
    "missing-validation",    # agent skipped a required check
    "hallucination",         # agent invented data not in context
    "wrong-tool-sequence",   # tools called in wrong order
    "context-loss",          # agent forgot earlier conversation context
    "boundary-not-enforced", # agent did something outside its scope
    "error-not-handled",     # tool failure not communicated to user
    "pii-leak",              # sensitive data included in response
}

def regression_by_root_cause(cases: list) -> dict:
    tag_counts = Counter(
        tag for c in cases
        for tag in c.tags
        if tag in ROOT_CAUSE_TAGS
    )
    return {
        "by_root_cause": dict(tag_counts),
        "top_cause": tag_counts.most_common(1)[0] if tag_counts else None,
        "uncategorised": sum(
            1 for c in cases
            if not any(t in ROOT_CAUSE_TAGS for t in c.tags)
        ),
    }

def regression_summary(cases: list, results: list[dict]) -> dict:
    """Full regression report with root-cause breakdown."""
    by_cause = regression_by_root_cause(cases)
    failed = {r["id"] for r in results if not r.get("passed")}
    failed_by_cause = Counter(
        tag for c in cases if c.id in failed
        for tag in c.tags if tag in ROOT_CAUSE_TAGS
    )
    return {
        "total_cases":    len(cases),
        "failed_cases":   len(failed),
        "by_root_cause":  by_cause,
        "failures_by_cause": dict(failed_by_cause),
    }
